#Requires -Version 5.1
<#
.SYNOPSIS
    Claude 인스턴스 부트스트랩 (Windows PowerShell)

.DESCRIPTION
    bootstrap-claude-instance.sh 의 Windows PowerShell 포팅.
    install-claude-npm.ps1 로 Claude Code 설치 + OAuth 인증을 끝낸 환경에,
    핵심 스킬/가이드/설정/플러그인을 ~/.claude/ 글로벌에 설치한다.
    설치할 콘텐츠는 이 스크립트 끝에 base64(tar.gz)로 임베드돼 있다.

    설치 항목
      - 스킬(15)    : handoff, resume, session-continuity, debug, refactor,
                      review, tidy, sdd, sdd-specify, sdd-plan, sdd-tasks,
                      sdd-implement, tdd-sprint, html-ppt, html-base
      - 가이드(전체) : guides/*
      - 전역 원칙    : CLAUDE.md.global -> ~/.claude/CLAUDE.md
      - HUD 설정     : claude-hud-config.json
      - 플러그인     : settings.json 의 enabledPlugins 선언
      - settings.json: permissions + env + plugins + statusLine 병합
      - alias        : PowerShell $PROFILE 에 cc/ca 함수 등록

    멱등성: 재실행 안전.

.EXAMPLE
    Set-ExecutionPolicy -Scope CurrentUser RemoteSigned
    .\bootstrap-claude-instance.ps1
#>

$ErrorActionPreference = "Stop"

$ClaudeDir = if ($env:CLAUDE_CONFIG_DIR) { $env:CLAUDE_CONFIG_DIR } else { Join-Path $env:USERPROFILE ".claude" }

Write-Host "=================================================" -ForegroundColor Cyan
Write-Host " Claude 인스턴스 부트스트랩 (Windows)"
Write-Host " (스킬 / 가이드 / 전역설정 / 플러그인 / alias)"
Write-Host "================================================="
Write-Host ""

# ---------------------------------------------------------------
# 1. 전제 확인
# ---------------------------------------------------------------
Write-Host "[1/8] 전제 확인..." -ForegroundColor Yellow

$claudeCmd = Get-Command claude -ErrorAction SilentlyContinue
if (-not $claudeCmd) {
    Write-Host "  X claude 가 설치돼 있지 않습니다. 먼저 install-claude-npm.ps1 를 실행하세요." -ForegroundColor Red
    exit 1
}
$claudeVer = & claude --version 2>$null
Write-Host "  OK claude 감지: $claudeVer" -ForegroundColor Green
Write-Host "  OK 설정 디렉터리: $ClaudeDir"
Write-Host ""

# ---------------------------------------------------------------
# 2. 임베드 payload 추출
# ---------------------------------------------------------------
Write-Host "[2/8] 임베드 payload 추출..." -ForegroundColor Yellow

$scriptContent = Get-Content -Path $PSCommandPath -Raw
$markerPattern = "(?m)^__PAYLOAD_BELOW__$"
$match = [regex]::Match($scriptContent, $markerPattern)

if (-not $match.Success) {
    Write-Host "  X payload 마커(__PAYLOAD_BELOW__)를 찾을 수 없습니다." -ForegroundColor Red
    exit 1
}

$payloadStart = $match.Index + $match.Length
$base64Payload = $scriptContent.Substring($payloadStart).Trim()

$stagingDir = Join-Path $env:TEMP "claude-bootstrap-$(Get-Random)"
New-Item -ItemType Directory -Path $stagingDir -Force | Out-Null

$tarGzPath = Join-Path $stagingDir "payload.tar.gz"
[System.IO.File]::WriteAllBytes($tarGzPath, [System.Convert]::FromBase64String($base64Payload))

tar -xzf $tarGzPath -C $stagingDir 2>$null
if ($LASTEXITCODE -ne 0) {
    Write-Host "  X payload 추출 실패. tar 명령이 필요합니다 (Windows 10+)." -ForegroundColor Red
    Remove-Item $stagingDir -Recurse -Force -ErrorAction SilentlyContinue
    exit 1
}
Remove-Item $tarGzPath -Force

Write-Host "  OK 추출 완료" -ForegroundColor Green
Write-Host ""

# ---------------------------------------------------------------
# 3. 스킬 설치
# ---------------------------------------------------------------
Write-Host "[3/8] 스킬 설치 -> $ClaudeDir\skills\" -ForegroundColor Yellow

$skillsTarget = Join-Path $ClaudeDir "skills"
if (-not (Test-Path $skillsTarget)) { New-Item -ItemType Directory -Path $skillsTarget -Force | Out-Null }

$skillsSrc = Join-Path $stagingDir "skills"
if (Test-Path $skillsSrc) {
    foreach ($skillDir in (Get-ChildItem -Path $skillsSrc -Directory)) {
        $dest = Join-Path $skillsTarget $skillDir.Name
        if (Test-Path $dest) { Remove-Item $dest -Recurse -Force }
        Copy-Item -Path $skillDir.FullName -Destination $dest -Recurse
        Write-Host "  OK $($skillDir.Name)" -ForegroundColor Green
    }
}
Write-Host ""

# ---------------------------------------------------------------
# 4. 가이드 설치
# ---------------------------------------------------------------
Write-Host "[4/8] 가이드 설치 -> $ClaudeDir\guides\" -ForegroundColor Yellow

$guidesTarget = Join-Path $ClaudeDir "guides"
if (-not (Test-Path $guidesTarget)) { New-Item -ItemType Directory -Path $guidesTarget -Force | Out-Null }

$guidesSrc = Join-Path $stagingDir "guides"
if (Test-Path $guidesSrc) {
    $guideFiles = Get-ChildItem -Path $guidesSrc -File
    Copy-Item -Path "$guidesSrc\*" -Destination $guidesTarget -Force
    Write-Host "  OK $($guideFiles.Count)개 가이드 복사" -ForegroundColor Green
}
Write-Host ""

# ---------------------------------------------------------------
# 5. 전역 CLAUDE.md 설치
# ---------------------------------------------------------------
Write-Host "[5/8] 전역 CLAUDE.md 설치..." -ForegroundColor Yellow

$claudeMdTarget = Join-Path $ClaudeDir "CLAUDE.md"
$claudeMdSrc    = Join-Path $stagingDir "templates\CLAUDE.md.global"

if (Test-Path $claudeMdTarget) {
    Copy-Item $claudeMdTarget "$claudeMdTarget.bak" -Force
    Write-Host "  - 기존 CLAUDE.md -> CLAUDE.md.bak 백업"
}
if (Test-Path $claudeMdSrc) {
    Copy-Item $claudeMdSrc $claudeMdTarget -Force
    Write-Host "  OK 완료" -ForegroundColor Green
}
Write-Host ""

# ---------------------------------------------------------------
# 6. claude-hud 설정
# ---------------------------------------------------------------
Write-Host "[6/8] claude-hud 설정..." -ForegroundColor Yellow

$hudTarget = Join-Path $ClaudeDir "plugins\claude-hud"
if (-not (Test-Path $hudTarget)) { New-Item -ItemType Directory -Path $hudTarget -Force | Out-Null }

$hudSrc = Join-Path $stagingDir "claude-config\claude-hud-config.json"
if (Test-Path $hudSrc) {
    Copy-Item $hudSrc (Join-Path $hudTarget "config.json") -Force
    Write-Host "  OK 완료" -ForegroundColor Green
}
Write-Host ""

# ---------------------------------------------------------------
# 7. settings.json 병합 (PowerShell 네이티브 — jq 불필요)
# ---------------------------------------------------------------
Write-Host "[7/8] settings.json 병합..." -ForegroundColor Yellow

$settingsPath = Join-Path $ClaudeDir "settings.json"
$fragmentPath = Join-Path $stagingDir "fragment.json"

# statusLine 의 __NODE_BIN__ placeholder 치환
$nodeBin = (Get-Command node -ErrorAction SilentlyContinue).Source
if (-not $nodeBin) { $nodeBin = "node" }
Write-Host "  - statusLine node 경로: $nodeBin"

if (Test-Path $fragmentPath) {
    $nodeEscaped = $nodeBin -replace '\\', '\\\\'
    $fragmentText = (Get-Content $fragmentPath -Raw) -replace "__NODE_BIN__", $nodeEscaped
    $fragment = $fragmentText | ConvertFrom-Json

    # 기존 settings 로드 (없으면 빈 객체)
    if (Test-Path $settingsPath) {
        Copy-Item $settingsPath "$settingsPath.bak" -Force
        Write-Host "  - 기존 settings.json -> settings.json.bak 백업"
        $settings = Get-Content $settingsPath -Raw | ConvertFrom-Json
    }
    else {
        $settings = [PSCustomObject]@{}
    }

    # 깊은 병합: fragment 의 키를 settings 에 덮어씀
    foreach ($prop in $fragment.PSObject.Properties) {
        if ($prop.Value -is [PSCustomObject] -and
            $settings.PSObject.Properties[$prop.Name] -and
            $settings.PSObject.Properties[$prop.Name].Value -is [PSCustomObject]) {
            # 1단계 깊은 병합
            $existing = $settings.PSObject.Properties[$prop.Name].Value
            foreach ($sub in $prop.Value.PSObject.Properties) {
                if ($existing.PSObject.Properties[$sub.Name]) {
                    $existing.PSObject.Properties[$sub.Name].Value = $sub.Value
                }
                else {
                    $existing | Add-Member -NotePropertyName $sub.Name -NotePropertyValue $sub.Value
                }
            }
        }
        else {
            if ($settings.PSObject.Properties[$prop.Name]) {
                $settings.PSObject.Properties[$prop.Name].Value = $prop.Value
            }
            else {
                $settings | Add-Member -NotePropertyName $prop.Name -NotePropertyValue $prop.Value
            }
        }
    }

    [System.IO.File]::WriteAllText($settingsPath, ($settings | ConvertTo-Json -Depth 10), [System.Text.UTF8Encoding]::new($false))
    Write-Host "  OK 병합 완료 (permissions/env/plugins/statusLine)" -ForegroundColor Green
}
Write-Host ""

# ---------------------------------------------------------------
# 8. alias 설치 (PowerShell $PROFILE 에 함수 등록)
# ---------------------------------------------------------------
Write-Host "[8/8] alias 설치 (PowerShell Profile)..." -ForegroundColor Yellow

$profilePath = $PROFILE
$profileDir  = Split-Path $profilePath -Parent
if (-not (Test-Path $profileDir)) { New-Item -ItemType Directory -Path $profileDir -Force | Out-Null }
if (-not (Test-Path $profilePath)) { New-Item -ItemType File -Path $profilePath -Force | Out-Null }

$markerBegin = "# >>> Claude Code aliases (bootstrap-claude-instance.ps1) >>>"
$markerEnd   = "# <<< Claude Code aliases (bootstrap-claude-instance.ps1) <<<"

$aliasBlock = @"

$markerBegin
function cc { `$env:IS_SANDBOX = '1'; claude --dangerously-skip-permissions @args }
function ca { claude agents @args }
$markerEnd
"@

$profileContent = Get-Content $profilePath -Raw -ErrorAction SilentlyContinue
if ($profileContent -and $profileContent.Contains($markerBegin)) {
    Write-Host "  - Profile에 이미 alias 등록됨 (스킵)"
}
else {
    Add-Content -Path $profilePath -Value $aliasBlock -Encoding UTF8
    Write-Host "  OK Profile에 cc/ca 함수 추가: $profilePath" -ForegroundColor Green
}
Write-Host ""

# ---------------------------------------------------------------
# 정리 + 검증
# ---------------------------------------------------------------
Remove-Item $stagingDir -Recurse -Force -ErrorAction SilentlyContinue

Write-Host "검증..." -ForegroundColor Yellow
$skillCount = (Get-ChildItem -Path (Join-Path $ClaudeDir "skills") -Directory -ErrorAction SilentlyContinue).Count
$guideCount = (Get-ChildItem -Path (Join-Path $ClaudeDir "guides") -Filter "*.md" -ErrorAction SilentlyContinue).Count
$settingsOk = if (Test-Path $settingsPath) { try { Get-Content $settingsPath -Raw | ConvertFrom-Json | Out-Null; "유효한 JSON" } catch { "X 손상됨" } } else { "없음" }

Write-Host "  스킬 디렉터리   : ${skillCount}개"
Write-Host "  가이드(.md)     : ${guideCount}개"
Write-Host "  settings.json   : $settingsOk"
Write-Host "  CLAUDE.md       : $(if (Test-Path (Join-Path $ClaudeDir 'CLAUDE.md')) { '설치됨' } else { '없음' })"
Write-Host "  HUD config      : $(if (Test-Path (Join-Path $ClaudeDir 'plugins\claude-hud\config.json')) { '설치됨' } else { '없음' })"
Write-Host ""

Write-Host "=================================================" -ForegroundColor Cyan
Write-Host " 부트스트랩 완료!"
Write-Host ""
Write-Host " 다음 단계:"
Write-Host "  1) 새 PowerShell 창을 열거나:  . `$PROFILE"
Write-Host "  2) claude 를 한 번 실행 -> enabledPlugins(superpowers/omc/claude-hud)가"
Write-Host "     공개 마켓에서 자동 설치됩니다."
Write-Host "  3) alias 사용:  cc (skip-permissions),  ca (agents)"
Write-Host ""
Write-Host " 주의: cc alias는 sandbox/개발 인스턴스 전용입니다."
Write-Host "       프로덕션 접근 가능한 환경에서는 사용하지 마세요."
Write-Host "================================================="

exit 0

__PAYLOAD_BELOW__

